export const getToolsByCategory = (category: string): AITool[] => {
  if (category === "All") return aiTools;
  return aiTools.filter(tool => tool.category === category);
};

export const searchTools = (query: string): AITool[] => {
  const lowercaseQuery = query.toLowerCase();
  return aiTools.filter(tool => 
    tool.title.toLowerCase().includes(lowercaseQuery) ||
    tool.description.toLowerCase().includes(lowercaseQuery) ||
    tool.category.toLowerCase().includes(lowercaseQuery)
  );
};

export const getPopularTools = (): AITool[] => {
  return aiTools.filter(tool => tool.isPopular);
};

export const getPremiumTools = (): AITool[] => {
  return aiTools.filter(tool => tool.isPremium);
};

export const getCategoryCount = (category: string): number => {
  if (category === "All") return aiTools.length;
  return aiTools.filter(tool => tool.category === category).length;
};
